19	  --navy:#0c1a2e;
20	  --navy2:#0f2340;
21	  --gray:#64748b;
22	  --gray-light:#94a3b8;
23	  --border:#e0eeff;
24	  --border2:rgba(14,165,233,0.2);
25	  --font:'Segoe UI',system-ui,-apple-system,sans-serif;
26	  --shadow:0 4px 24px rgba(14,165,233,0.12);
27	  --shadow-lg:0 12px 48px rgba(14,165,233,0.18);
28	}
29	html{scroll-behavior:smooth;}
30	body{font-family:var(--font);background:var(--white);color:var(--navy);overflow-x:hidden;}
31	a{text-decoration:none;color:inherit;}
32	
33	/* ========== CANVAS ========== */
34	#cvs{position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;opacity:.5;}
35	
36	/* ========== UTILITY ========== */
37	.wrap{max-width:1180px;margin:0 auto;padding:0 28px;position:relative;z-index:2;}
38	.chip{display:inline-flex;align-items:center;gap:7px;background:rgba(14,165,233,0.08);
39	  border:1px solid rgba(14,165,233,0.25);color:var(--azure-mid);
40	  font-size:.75rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;
41	  padding:5px 15px;border-radius:30px;margin-bottom:14px;}
42	.chip .blink{width:7px;height:7px;background:var(--azure);border-radius:50%;
43	  animation:blk 1.6s ease-in-out infinite;}
44	@keyframes blk{0%,100%{opacity:1;transform:scale(1);}50%{opacity:.3;transform:scale(1.6);}}
45	.h2{font-size:clamp(1.9rem,3.2vw,2.8rem);font-weight:800;line-height:1.12;margin-bottom:14px;color:var(--navy);}
46	.h2 em{color:var(--azure);font-style:normal;}
47	.lead{font-size:1.02rem;color:var(--gray);line-height:1.8;max-width:620px;}
48	.bar{width:48px;height:3px;background:linear-gradient(90deg,var(--azure),var(--blue-200));border-radius:3px;margin:0 0 28px;}
49	
50	.btn{display:inline-flex;align-items:center;gap:8px;padding:13px 28px;border-radius:8px;
51	  font-weight:700;font-size:.93rem;cursor:pointer;border:none;transition:all .25s;}
52	.btn-blue{background:var(--azure);color:var(--white);box-shadow:0 4px 18px rgba(14,165,233,0.3);}
53	.btn-blue:hover{background:var(--azure-mid);transform:translateY(-2px);box-shadow:0 8px 28px rgba(14,165,233,0.4);}
54	.btn-outline{background:transparent;border:2px solid var(--azure);color:var(--azure);}
55	.btn-outline:hover{background:var(--azure);color:var(--white);}
56	.btn-white{background:var(--white);color:var(--azure-mid);font-weight:800;}
57	.btn-white:hover{background:var(--blue-100);}
58	
59	/* reveal */
60	.rv{opacity:0;transform:translateY(28px);transition:opacity .7s ease,transform .7s ease;}
61	.rv.in{opacity:1;transform:translateY(0);}
62	.rv.d1{transition-delay:.1s;}
63	.rv.d2{transition-delay:.2s;}
64	.rv.d3{transition-delay:.3s;}
65	.rv.d4{transition-delay:.4s;}
66	
67	/* ========== TOPBAR ========== */
68	.topbar{background:var(--navy);padding:7px 0;}
69	.topbar .wrap{display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap;}
70	.topbar p{font-size:.8rem;color:rgba(255,255,255,.55);}
71	.topbar p a{color:var(--azure);margin:0 5px;}
72	.topbar-r{display:flex;gap:14px;font-size:.8rem;}
73	.topbar-r a{color:rgba(255,255,255,.5);transition:color .2s;}
74	.topbar-r a:hover,.topbar-r a.on{color:var(--azure);}
75	
76	/* ========== NAVBAR ========== */
77	.nav{position:sticky;top:0;z-index:999;background:rgba(255,255,255,.97);
78	  backdrop-filter:blur(12px);border-bottom:1px solid var(--border);
79	  box-shadow:0 2px 20px rgba(14,165,233,0.07);}
80	.nav .wrap{display:flex;align-items:center;justify-content:space-between;height:66px;}

