/* Hero Right — Trivium Animated Logo */
.hero-visual{display:flex;align-items:center;justify-content:center;}

/* Outer wrapper with animated blue background */
.logo-scene{
  position:relative;
  width:420px;height:420px;
  display:flex;align-items:center;justify-content:center;
}
/* Animated radial blue bg */
.logo-scene::before{
  content:'';
  position:absolute;inset:0;border-radius:50%;
  background:radial-gradient(circle at 50% 50%,
    rgba(14,165,233,.22) 0%,
    rgba(2,132,199,.14) 35%,
    rgba(12,26,46,.0) 70%);
  animation:bgPulse 3.5s ease-in-out infinite;
}
.logo-scene::after{
  content:'';
  position:absolute;inset:-30px;border-radius:50%;
  background:radial-gradient(circle at 50% 50%,
    rgba(0,212,232,.08) 0%,
    transparent 65%);
  animation:bgPulse 3.5s ease-in-out infinite reverse;
}
@keyframes bgPulse{
  0%,100%{transform:scale(1);opacity:1;}
  50%{transform:scale(1.18);opacity:.6;}
}

/* Glow rings */
.t-ring{
  position:absolute;border-radius:50%;
  border:1px solid rgba(14,165,233,0.18);
  animation:ringPulse 3.2s ease-in-out infinite;
  pointer-events:none;
}
.t-ring:nth-child(1){width:240px;height:240px;animation-delay:0s;
  border-color:rgba(14,165,233,.30);}
.t-ring:nth-child(2){width:310px;height:310px;animation-delay:.6s;
  border-color:rgba(14,165,233,.18);}
.t-ring:nth-child(3){width:380px;height:380px;animation-delay:1.2s;
  border-color:rgba(14,165,233,.1);}
.t-ring:nth-child(4){width:420px;height:420px;animation-delay:1.8s;
  border-color:rgba(14,165,233,.06);}
@keyframes ringPulse{
  0%,100%{opacity:1;transform:scale(1);}
  50%{opacity:.2;transform:scale(1.05);}
}

/* SVG logo */
.trivium-logo-hero{
  width:220px;height:220px;
  filter:drop-shadow(0 0 28px rgba(0,200,224,.55))
         drop-shadow(0 0 8px rgba(0,200,224,.3));
  animation:logoFloat 4.5s ease-in-out infinite;
  position:relative;z-index:2;
}
@keyframes logoFloat{
  0%,100%{transform:translateY(0) rotate(0deg);}
  50%{transform:translateY(-14px) rotate(1deg);}
}

/* Tagline under logo */
.logo-tagline{
  position:absolute;bottom:28px;left:50%;transform:translateX(-50%);
  text-align:center;z-index:3;white-space:nowrap;
}
.logo-tagline .lt-name{
  font-size:1.5rem;font-weight:900;color:var(--white);letter-spacing:.06em;display:block;
  text-shadow:0 0 30px rgba(14,165,233,.5);
}
.logo-tagline .lt-sub{
  font-size:.72rem;font-weight:600;color:rgba(14,165,233,.8);
  letter-spacing:.18em;text-transform:uppercase;margin-top:4px;display:block;
}

/* Orbiting dot */
.orbit-wrap{
  position:absolute;width:310px;height:310px;
  animation:orbit 8s linear infinite;
  pointer-events:none;z-index:1;
}
.orbit-dot{
  position:absolute;top:-5px;left:50%;transform:translateX(-50%);
  width:10px;height:10px;border-radius:50%;
  background:var(--azure);
  box-shadow:0 0 14px 4px rgba(14,165,233,.6);
}
.orbit-wrap2{
  position:absolute;width:240px;height:240px;
  animation:orbit 5s linear infinite reverse;
  pointer-events:none;z-index:1;
}
.orbit-dot2{
  position:absolute;bottom:-4px;left:50%;transform:translateX(-50%);
  width:7px;height:7px;border-radius:50%;
  background:#38bdf8;
  box-shadow:0 0 10px 3px rgba(56,189,248,.5);
}
@keyframes orbit{from{transform:rotate(0deg);}to{transform:rotate(360deg);}}

