7	<style>
8	/* ========== RESET & VARIABLES ========== */
9	*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
10	:root{
11	  --bg-deep:#1a1e24;
12	  --bg-card:#22272f;
13	  --bg-card2:#2a3040;
