18	  --white:#ffffff;
19	  --gray:#8896a8;
20	  --gray2:#b0bec5;
21	  --border:rgba(0,212,232,0.15);
22	  --font:'Segoe UI',system-ui,sans-serif;
23	  --radius:14px;
24	}
25	html{scroll-behavior:smooth;}
26	body{font-family:var(--font);background:var(--bg-deep);color:var(--white);overflow-x:hidden;}
27	a{text-decoration:none;color:inherit;}
28	img{display:block;max-width:100%;}
29	
30	/* ========== CANVAS PARTICLES ========== */
31	#particles{position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;}
32	
33	/* ========== UTILITY ========== */
34	.container{max-width:1160px;margin:0 auto;padding:0 28px;position:relative;z-index:1;}
35	.tag{display:inline-flex;align-items:center;gap:7px;background:rgba(0,212,232,0.1);
