42	.sec-sub{font-size:1rem;color:var(--gray2);line-height:1.75;max-width:620px;}
43	.divider{width:50px;height:3px;background:linear-gradient(90deg,var(--cyan),transparent);border-radius:3px;margin:0 0 28px;}
