1256	const c=document.getElementById('cvs');
1257	const cx=c.getContext('2d');
1258	let W,H,pts=[];
1259	function rs(){W=c.width=window.innerWidth;H=c.height=window.innerHeight;}
1260	rs();window.addEventListener('resize',rs);
1261	function rb(a,b){return Math.random()*(b-a)+a;}
1262	for(let i=0;i<60;i++) pts.push({x:rb(0,W),y:rb(0,H),vx:rb(-.25,.25),vy:rb(-.25,.25),r:rb(1,2.5),o:rb(.06,.18)});
1263	function drawPts(){
1264	  cx.clearRect(0,0,W,H);
1265	  pts.forEach((p,i)=>{
1266	    pts.slice(i+1).forEach(q=>{
1267	      const d=Math.hypot(p.x-q.x,p.y-q.y);
1268	      if(d<130){cx.beginPath();cx.strokeStyle=`rgba(14,165,233,${.1*(1-d/130)})`;cx.lineWidth=.8;cx.moveTo(p.x,p.y);cx.lineTo(q.x,q.y);cx.stroke();}
1269	    });
1270	    cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);
1271	    cx.fillStyle=`rgba(14,165,233,${p.o})`;cx.fill();
1272	    p.x+=p.vx;p.y+=p.vy;
1273	    if(p.x<0||p.x>W)p.vx*=-1;if(p.y<0||p.y>H)p.vy*=-1;
1274	  });
1275	  requestAnimationFrame(drawPts);
1276	}
1277	drawPts();
