  dots.push({
    x: randBetween(0,W), y: randBetween(0,H),
    vx: randBetween(-.3,.3), vy: randBetween(-.3,.3),
    r: randBetween(1,2.5), o: randBetween(.15,.5)
  });
}
function drawParticles(){
  ctx.clearRect(0,0,W,H);
  // lines between close dots
  for(let i=0;i<dots.length;i++){
    for(let j=i+1;j<dots.length;j++){
      const dx=dots[i].x-dots[j].x, dy=dots[i].y-dots[j].y;
      const d=Math.sqrt(dx*dx+dy*dy);
      if(d<140){
        ctx.beginPath();
        ctx.strokeStyle=`rgba(0,212,232,${.12*(1-d/140)})`;
        ctx.lineWidth=.8;
        ctx.moveTo(dots[i].x,dots[i].y);
        ctx.lineTo(dots[j].x,dots[j].y);
        ctx.stroke();
      }
    }
  }
  // dots
  dots.forEach(d=>{
    ctx.beginPath();
    ctx.arc(d.x,d.y,d.r,0,Math.PI*2);
    ctx.fillStyle=`rgba(0,212,232,${d.o})`;
    ctx.fill();
    d.x+=d.vx; d.y+=d.vy;
    if(d.x<0||d.x>W) d.vx*=-1;
    if(d.y<0||d.y>H) d.vy*=-1;
  });
  requestAnimationFrame(drawParticles);
}
drawParticles();

// ---- SCROLL REVEAL ----
const reveals = document.querySelectorAll('.reveal');
const observer = new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(e.isIntersecting){e.target.classList.add('visible');observer.unobserve(e.target);}
  });
},{threshold:0.1});
reveals.forEach(r=>observer.observe(r));

// ---- COUNTER ANIMATION ----
function animateCounter(el){
  const target = parseInt(el.dataset.count);
  let current = 0;
  const step = Math.ceil(target/60);
  const timer = setInterval(()=>{
    current = Math.min(current+step, target);
    el.textContent = current + (el.classList.contains('sn') || el.parentElement.classList.contains('hstat') ? (el.dataset.count==='99'?'%':'+') : '+');
    if(current>=target) clearInterval(timer);
  },25);
}
const counterObs = new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      e.target.querySelectorAll('[data-count]').forEach(animateCounter);
      counterObs.unobserve(e.target);
    }
  });
},{threshold:.3});
document.querySelectorAll('.hero-stats,.ab-stats,#stats').forEach(s=>counterObs.observe(s));

// ---- PRODUCT TABS ----
const panelMap = {all:'panel-all',iot:'panel-iot',cloud:'panel-cloud',ai:'panel-ai'};
function switchTab(btn,key){
  document.querySelectorAll('.ptab').forEach(t=>t.classList.remove('active'));
  document.querySelectorAll('.products-panel').forEach(p=>p.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById(panelMap[key]).classList.add('active');
}

// ---- BILLING TOGGLE ----
let isYearly = true;
function toggleBilling(){
  isYearly = !isYearly;
  document.getElementById('billingToggle').classList.toggle('on', isYearly);
  document.querySelectorAll('.price-val').forEach(el=>{
    const val = isYearly ? el.dataset.yearly : el.dataset.monthly;
    el.textContent = '€'+val;
  });
  document.querySelectorAll('.plan .price span').forEach(el=>{
    el.textContent = isYearly ? '/ mese · fatturato annualmente' : '/ mese · fatturato mensilmente';
  });
}

// ---- FAQ ACCORDION ----
function toggleFaq(item){
  const isOpen = item.classList.contains('open');
  document.querySelectorAll('.faq-item').forEach(f=>{
    f.classList.remove('open');
    f.querySelector('.faq-a').classList.remove('open');
  });
  if(!isOpen){
    item.classList.add('open');
    item.querySelector('.faq-a').classList.add('open');
  }
}

// ---- FORM SUBMIT ----
function handleSubmit(e){
  e.preventDefault();
  const btn = e.target.querySelector('button[type=submit]');
  btn.textContent = '✓ Richiesta Inviata!';
  btn.style.background = '#00a040';
  btn.disabled = true;
  setTimeout(()=>{
    btn.textContent = 'Invia Richiesta →';
    btn.style.background = '';
    btn.disabled = false;
    e.target.reset();
  },3500);
}

// ---- NAVBAR ACTIVE ----
const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-links a');
window.addEventListener('scroll',()=>{
  let cur='';
  sections.forEach(s=>{
    if(pageYOffset >= s.offsetTop-120) cur=s.id;
  });
  navLinks.forEach(a=>{
    a.classList.toggle('active', a.getAttribute('href')==='#'+cur);
  });
});
</script>
</body>
</html>

